/**
 * Regression contracts for goal/session branch push safety.
 *
 * Git effects are represented by a deterministic CommandRunner so tier 1 pins
 * Bobbit's decisions without spawning Git. Real publication fidelity belongs in
 * the E2E tier.
 */
import { describe, it } from "vitest";
import assert from "node:assert/strict";
import fs from "node:fs";
import path from "node:path";
import type { CommandRunner } from "../../src/server/gateway-deps.ts";

import { WorktreePool } from "../../src/server/agent/worktree-pool.ts";
import {
	buildDefaultWorkflows,
	readyToMergeGate,
	type SeededVerifyStep,
} from "../../src/server/state-migration/seed-default-workflows.ts";
import {
	PROJECT_ASSISTANT_PROMPT,
	PROJECT_ASSISTANT_SCAFFOLDING_PROMPT,
} from "../../src/server/agent/project-assistant.ts";

const SAFE_BRANCH_REFSPEC = "{{branch}}:refs/heads/{{branch}}";
const BARE_BRANCH_PUSH = /git push origin \{\{branch\}\}(?!:)/;

interface FakePoolGit {
	commands: string[];
	state: {
		branch: string;
		upstream: string | null;
	};
	runner: CommandRunner;
}

function fakePoolGit(repoPath: string, poolBranch: string): FakePoolGit {
	const commands: string[] = [];
	const state = { branch: poolBranch, upstream: "origin/master" as string | null };
	const record = (args: readonly string[]) => commands.push(`git ${args.join(" ")}`);
	return {
		commands,
		state,
		runner: {
			execFileSync(file, args) {
				assert.equal(file, "git");
				record(args);
				if (args[0] === "rev-parse" && args[1] === "--show-toplevel") return repoPath;
				throw new Error(`unexpected synchronous git command: ${args.join(" ")}`);
			},
			async execFile(file, args) {
				assert.equal(file, "git");
				record(args);

				if (args[0] === "branch" && args[1] === "-m") {
					assert.equal(args[2], state.branch);
					state.branch = String(args[3]);
				} else if (args[0] === "branch" && args[1] === "--unset-upstream") {
					assert.equal(args[2], state.branch);
					state.upstream = null;
				} else if (args[0] === "for-each-ref") {
					assert.equal(args.at(-1), `refs/heads/${state.branch}`);
					return { stdout: state.upstream ? `${state.upstream}\n` : "", stderr: "" };
				} else if (args[0] === "symbolic-ref") {
					return { stdout: "refs/remotes/origin/master\n", stderr: "" };
				}
				return { stdout: "", stderr: "" };
			},
		},
	};
}

function branchPushStep(steps: SeededVerifyStep[] | undefined): string {
	const step = steps?.find((candidate) => candidate.type === "command"
		&& typeof candidate.run === "string"
		&& candidate.run.includes("git push origin"));
	assert.ok(step?.run, "ready-to-merge gate must include a git push command step");
	return step.run;
}

function pushArgsFromTemplate(template: string, branch: string): string[] {
	const pushCommand = template.replaceAll("{{branch}}", branch).split("&&", 1)[0].trim();
	assert.match(pushCommand, /^git push origin\b/, `expected a git push origin command, got: ${pushCommand}`);
	return pushCommand.split(/\s+/).slice(1);
}

function assertSafeBranchPushTemplate(label: string, template: string): void {
	assert.ok(
		template.includes(SAFE_BRANCH_REFSPEC),
		`${label} must push with explicit destination refspec ${SAFE_BRANCH_REFSPEC}; got: ${template}`,
	);
	assert.doesNotMatch(
		template,
		BARE_BRANCH_PUSH,
		`${label} must not use bare git push origin {{branch}} because upstream config can target origin/master`,
	);
}

async function claimFakePoolBranch(poolBranch: string, targetBranch: string): Promise<{
	commands: string[];
	state: FakePoolGit["state"];
}> {
	const repoPath = path.join(process.cwd(), ".virtual-goal-push-repo");
	const poolWorktree = path.join(process.cwd(), ".virtual-goal-push-worktrees", poolBranch.replaceAll("/", "-"));
	const fake = fakePoolGit(repoPath, poolBranch);
	const pool = new WorktreePool({ repoPath, targetSize: 0, commandRunner: fake.runner });
	pool.registerExternalEntry(poolBranch, poolWorktree);
	try {
		const claim = await pool.claim(targetBranch);
		assert.ok(claim, "pool claim should succeed");
		await pool.stop();
		return { commands: fake.commands, state: fake.state };
	} finally {
		await pool.stop();
	}
}

describe("goal/session branch push safety regressions", () => {
	it("claiming a pool branch must not preserve an inherited origin/master upstream", async () => {
		const { commands, state } = await claimFakePoolBranch("pool/_pool-upstream", "goal/foo");

		assert.equal(state.branch, "goal/foo");
		assert.equal(state.upstream, null, "claimed branch must not retain inherited origin/master");
		assert.ok(commands.includes("git branch --unset-upstream goal/foo"), `claim must explicitly clear upstream; commands:\n${commands.join("\n")}`);
		assert.ok(commands.includes("git config --unset-all branch.goal/foo.remote"));
		assert.ok(commands.includes("git config --unset-all branch.goal/foo.merge"));
	});

	it("claimed pool branch stays local-only even when push is enabled", async () => {
		const { commands, state } = await claimFakePoolBranch("pool/_pool-local-only", "goal/foo");

		assert.equal(state.upstream, null);
		assert.ok(!commands.some((command) => command.startsWith("git push ")), `pool claim/freshen must not push; commands:\n${commands.join("\n")}`);
		assert.ok(
			!commands.includes("git branch --set-upstream-to=origin/goal/foo goal/foo"),
			`pool claim/freshen must not install a remote upstream; commands:\n${commands.join("\n")}`,
		);
	});

	it("canonical ready-to-merge push must not update origin/master from a goal branch", () => {
		const template = branchPushStep(readyToMergeGate().verify);
		assert.deepEqual(
			pushArgsFromTemplate(template, "goal/foo"),
			["push", "origin", "goal/foo:refs/heads/goal/foo"],
		);
		assert.doesNotMatch(template, /goal\/foo:refs\/heads\/master/);
	});

	it("server branch publish helper uses shell-free git argv refspecs", () => {
		const source = fs.readFileSync(new URL("../../src/server/server.ts", import.meta.url), "utf-8");
		assert.match(source, /runner\.execFile\("git", args, \{ cwd, encoding: "utf-8", timeout \}\)/);
		assert.match(source, /push: \["push", "origin", `HEAD:refs\/heads\/\$\{branch\}`\]/);
		assert.match(source, /fetchRemoteTracking: \["fetch", "origin", `refs\/heads\/\$\{branch\}:refs\/remotes\/origin\/\$\{branch\}`\]/);
		assert.match(source, /setUpstream: \["branch", `--set-upstream-to=origin\/\$\{branch\}`, branch\]/);
		assert.doesNotMatch(source, /function shellQuote|safeBranchPublishCommand/);
	});

	it("canonical seeded ready-to-merge gates use explicit branch refspecs", () => {
		assertSafeBranchPushTemplate("readyToMergeGate()", branchPushStep(readyToMergeGate().verify));

		for (const [workflowId, workflow] of Object.entries(buildDefaultWorkflows("app"))) {
			const gate = workflow.gates.find((candidate) => candidate.id === "ready-to-merge");
			assert.ok(gate, `${workflowId} workflow must have ready-to-merge gate`);
			assertSafeBranchPushTemplate(`${workflowId}.ready-to-merge`, branchPushStep(gate.verify));
		}
	});

	it("project-assistant workflow prompts teach explicit branch refspecs", () => {
		for (const [label, prompt] of [
			["PROJECT_ASSISTANT_PROMPT", PROJECT_ASSISTANT_PROMPT],
			["PROJECT_ASSISTANT_SCAFFOLDING_PROMPT", PROJECT_ASSISTANT_SCAFFOLDING_PROMPT],
		] as const) {
			assert.ok(
				prompt.includes(SAFE_BRANCH_REFSPEC),
				`${label} must teach explicit ready-to-merge branch push refspec ${SAFE_BRANCH_REFSPEC}`,
			);
			assert.doesNotMatch(prompt, BARE_BRANCH_PUSH, `${label} must not recommend bare git push origin {{branch}}`);
		}
	});
});
